-- OsorIA Ecommerce baseline: ecommerce schema only. Never create ecommerce tables in public.
create schema if not exists ecommerce;
create extension if not exists pgcrypto with schema extensions;

do $$
begin
  if not exists (select 1 from pg_type t join pg_namespace n on n.oid=t.typnamespace where n.nspname='ecommerce' and t.typname='address_type') then create type ecommerce.address_type as enum ('billing','shipping'); end if;
  if not exists (select 1 from pg_type t join pg_namespace n on n.oid=t.typnamespace where n.nspname='ecommerce' and t.typname='cart_status') then create type ecommerce.cart_status as enum ('active','abandoned','expired'); end if;
  if not exists (select 1 from pg_type t join pg_namespace n on n.oid=t.typnamespace where n.nspname='ecommerce' and t.typname='inventory_movement_type') then create type ecommerce.inventory_movement_type as enum ('in','out','adjustment','reserve','release'); end if;
  if not exists (select 1 from pg_type t join pg_namespace n on n.oid=t.typnamespace where n.nspname='ecommerce' and t.typname='order_status') then create type ecommerce.order_status as enum ('pending','confirmed','processing','shipped','delivered','returned','cancelled'); end if;
  if not exists (select 1 from pg_type t join pg_namespace n on n.oid=t.typnamespace where n.nspname='ecommerce' and t.typname='payment_status') then create type ecommerce.payment_status as enum ('pending','paid','failed','refunded','cancelled'); end if;
end $$;

create table if not exists ecommerce.stores (id uuid primary key default gen_random_uuid(), subdomain varchar not null unique, store_name varchar not null, domain varchar not null default 'tudominio.com', is_active boolean default true, is_public boolean default true, currency_code varchar not null default 'COP', created_at timestamptz default now(), updated_at timestamptz default now(), deleted_at timestamptz);
create table if not exists ecommerce.user_profiles (id uuid primary key references auth.users(id) on delete cascade, email varchar not null unique, first_name varchar, last_name varchar, role varchar not null default 'user' check (role in ('user','admin','super_admin')), created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists ecommerce.app_themes (id bigint generated by default as identity primary key, theme_name text not null unique, colors jsonb not null, is_active boolean default false, created_at timestamptz not null default timezone('utc', now()), updated_at timestamptz not null default timezone('utc', now()));
create table if not exists ecommerce.app_fonts (id bigint generated by default as identity primary key, font_name text not null unique, font_family text not null, font_display_name text, google_font_url text, css_font_family text not null, is_active boolean default false, created_at timestamptz not null default timezone('utc', now()), updated_at timestamptz not null default timezone('utc', now()));

create table if not exists ecommerce.roles (id uuid primary key default gen_random_uuid(), store_id uuid not null references ecommerce.stores(id) on delete cascade, role_name varchar not null, description text, is_system boolean default false, created_at timestamptz default now(), unique (store_id, role_name));
create table if not exists ecommerce.permissions (id uuid primary key default gen_random_uuid(), perm_key varchar not null unique, description text);
create table if not exists ecommerce.role_permissions (role_id uuid not null references ecommerce.roles(id) on delete cascade, permission_id uuid not null references ecommerce.permissions(id) on delete cascade, primary key (role_id, permission_id));
create table if not exists ecommerce.store_users (id uuid primary key default gen_random_uuid(), store_id uuid not null references ecommerce.stores(id) on delete cascade, user_id uuid not null references ecommerce.user_profiles(id) on delete cascade, created_at timestamptz default now(), updated_at timestamptz default now(), unique (store_id, user_id));
create table if not exists ecommerce.store_user_roles (store_user_id uuid not null references ecommerce.store_users(id) on delete cascade, role_id uuid not null references ecommerce.roles(id) on delete cascade, primary key (store_user_id, role_id));

create table if not exists ecommerce.item_categories (id uuid primary key default gen_random_uuid(), store_id uuid not null references ecommerce.stores(id) on delete cascade, category_name varchar not null, category_description text, category_image_url text, parent_category_id uuid references ecommerce.item_categories(id) on delete set null, display_order integer default 0, is_active boolean default true, created_at timestamptz default now(), updated_at timestamptz default now(), unique (store_id, category_name));
create table if not exists ecommerce.store_items (id uuid primary key default gen_random_uuid(), store_id uuid not null references ecommerce.stores(id) on delete cascade, item_code varchar, item_name varchar not null, item_description text, item_description_html text, category_id uuid references ecommerce.item_categories(id) on delete set null, base_price numeric not null default 0, compare_at_price numeric, currency_code varchar not null default 'COP', is_active boolean default true, is_featured boolean default false, is_available_for_sale boolean default true, track_inventory boolean default false, inventory_quantity integer default 0, low_stock_threshold integer default 10, item_slug varchar, seo_title varchar, seo_description text, tags varchar[] default array[]::varchar[], primary_image_url text, primary_image_alt text, metadata jsonb default '{}'::jsonb, display_order integer default 0, created_at timestamptz default now(), updated_at timestamptz default now());
create unique index if not exists store_items_store_code_unique on ecommerce.store_items(store_id, item_code) where item_code is not null;
create unique index if not exists store_items_store_slug_unique on ecommerce.store_items(store_id, item_slug) where item_slug is not null;
create table if not exists ecommerce.item_variants (id uuid primary key default gen_random_uuid(), item_id uuid not null references ecommerce.store_items(id) on delete cascade, variant_code varchar, price numeric, compare_at_price numeric, variant_options jsonb default '{}'::jsonb, track_inventory boolean default false, inventory_quantity integer default 0, is_available boolean default true, is_default boolean default false, metadata jsonb default '{}'::jsonb, created_at timestamptz default now(), updated_at timestamptz default now(), unique (item_id, variant_code));
create table if not exists ecommerce.item_images (id uuid primary key default gen_random_uuid(), item_id uuid references ecommerce.store_items(id) on delete cascade, variant_id uuid references ecommerce.item_variants(id) on delete cascade, image_url text not null, image_alt text, image_title text, display_order integer default 0, width integer, height integer, image_type varchar default 'product', created_at timestamptz default now(), check (item_id is not null or variant_id is not null));
create table if not exists ecommerce.item_metrics (item_id uuid primary key references ecommerce.store_items(id) on delete cascade, view_count integer not null default 0, updated_at timestamptz default now());
create table if not exists ecommerce.item_seo (item_id uuid primary key references ecommerce.store_items(id) on delete cascade, seo_title varchar, seo_description text, updated_at timestamptz default now());
create table if not exists ecommerce.item_tags (item_id uuid not null references ecommerce.store_items(id) on delete cascade, tag varchar not null, primary key (item_id, tag));
create table if not exists ecommerce.item_options (id uuid primary key default gen_random_uuid(), item_id uuid not null references ecommerce.store_items(id) on delete cascade, option_name varchar not null, display_order integer default 0, is_required boolean default true, created_at timestamptz default now());
create table if not exists ecommerce.item_option_values (id uuid primary key default gen_random_uuid(), option_id uuid not null references ecommerce.item_options(id) on delete cascade, value_text varchar not null, display_order integer default 0);

create table if not exists ecommerce.carts (id uuid primary key default gen_random_uuid(), store_id uuid not null references ecommerce.stores(id) on delete cascade, user_id uuid, session_id text, currency_code varchar not null default 'COP', status ecommerce.cart_status default 'active', created_at timestamptz default now(), updated_at timestamptz default now(), expires_at timestamptz default (now() + interval '30 days'));
create table if not exists ecommerce.cart_items (id uuid primary key default gen_random_uuid(), cart_id uuid not null references ecommerce.carts(id) on delete cascade, variant_id uuid references ecommerce.item_variants(id) on delete set null, quantity integer not null default 1 check (quantity > 0), unit_price numeric not null, selected_options jsonb, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists ecommerce.orders (id uuid primary key default gen_random_uuid(), store_id uuid not null references ecommerce.stores(id) on delete restrict, order_number varchar not null default (('ORD-' || to_char(now(), 'YYYY')) || '-000001'), order_date timestamptz default now(), status ecommerce.order_status default 'pending', customer_type varchar default 'guest' check (customer_type in ('guest','user')), user_id uuid, customer_email varchar not null, customer_first_name varchar, customer_last_name varchar, customer_phone varchar, shipping_address varchar, shipping_city varchar, shipping_postal_code varchar, shipping_country varchar, shipping_notes varchar, payment_method varchar, payment_status ecommerce.payment_status default 'pending', payment_reference varchar, subtotal numeric not null default 0, shipping_cost numeric default 0, tax_amount numeric default 0, discount_amount numeric default 0, total_amount numeric not null default 0, currency_code varchar not null default 'COP', notes text, metadata jsonb default '{}'::jsonb, confirmed_at timestamptz, shipped_at timestamptz, delivered_at timestamptz, cancelled_at timestamptz, created_at timestamptz default now(), updated_at timestamptz default now(), unique (store_id, order_number));
create table if not exists ecommerce.order_items (id uuid primary key default gen_random_uuid(), order_id uuid not null references ecommerce.orders(id) on delete cascade, product_id uuid references ecommerce.store_items(id) on delete set null, product_name varchar not null, product_sku varchar, variant_id uuid references ecommerce.item_variants(id) on delete set null, variant_title varchar, unit_price numeric not null, quantity integer not null default 1 check (quantity > 0), total_price numeric not null, currency_code varchar not null default 'COP', product_image_url text, product_slug varchar, selected_options jsonb default '{}'::jsonb, metadata jsonb default '{}'::jsonb, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists ecommerce.order_addresses (id uuid primary key default gen_random_uuid(), order_id uuid not null references ecommerce.orders(id) on delete cascade, address_type text default 'shipping', address_line_1 text, city varchar, postal_code varchar, country varchar default 'Colombia', created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists ecommerce.payment_transactions (id uuid primary key default gen_random_uuid(), order_id uuid not null references ecommerce.orders(id) on delete cascade, provider varchar not null, transaction_type varchar default 'payment', provider_payment_method varchar, provider_transaction_id varchar, provider_txn_id varchar, status ecommerce.payment_status not null, amount numeric not null, currency_code varchar not null default 'COP', metadata jsonb default '{}'::jsonb, raw_response jsonb, created_at timestamptz default now());
create table if not exists ecommerce.shipments (id uuid primary key default gen_random_uuid(), order_id uuid not null references ecommerce.orders(id) on delete cascade, carrier varchar not null, tracking_number varchar, shipped_at timestamptz, delivered_at timestamptz, status varchar default 'in_transit', metadata jsonb default '{}'::jsonb);
create table if not exists ecommerce.inventory_movements (id uuid primary key default gen_random_uuid(), store_id uuid not null references ecommerce.stores(id) on delete cascade, variant_id uuid not null references ecommerce.item_variants(id) on delete cascade, movement_type ecommerce.inventory_movement_type not null, quantity integer not null check (quantity <> 0), reason text, related_order_id uuid references ecommerce.orders(id) on delete set null, related_cart_id uuid references ecommerce.carts(id) on delete set null, created_at timestamptz default now());

create table if not exists ecommerce.component_styles (id bigint generated by default as identity primary key, store_id uuid not null references ecommerce.stores(id) on delete cascade, component_name text not null, variables jsonb not null, updated_at timestamptz default now(), unique (store_id, component_name));
create table if not exists ecommerce.app_theme_versions (id uuid primary key default gen_random_uuid(), store_id uuid not null references ecommerce.stores(id) on delete cascade, theme_id bigint not null references ecommerce.app_themes(id) on delete cascade, fonts jsonb, variables jsonb, is_current boolean default false, created_at timestamptz default now(), unique (store_id, theme_id));
create table if not exists ecommerce.store_branding (store_id uuid primary key references ecommerce.stores(id) on delete cascade, logo_url text, favicon_url text, primary_color varchar, secondary_color varchar, updated_at timestamptz default now());
create table if not exists ecommerce.store_commerce_settings (store_id uuid primary key references ecommerce.stores(id) on delete cascade, tax_rate numeric default 0, shipping_enabled boolean default true, free_shipping_threshold numeric, updated_at timestamptz default now());
create table if not exists ecommerce.store_contact (store_id uuid primary key references ecommerce.stores(id) on delete cascade, contact_email varchar, contact_phone varchar, address text, updated_at timestamptz default now());
create table if not exists ecommerce.store_integrations (store_id uuid primary key references ecommerce.stores(id) on delete cascade, shopify_store_domain varchar, shopify_access_token text, metadata jsonb default '{}'::jsonb, updated_at timestamptz default now());
create table if not exists ecommerce.store_seo (store_id uuid primary key references ecommerce.stores(id) on delete cascade, seo_title varchar, seo_description text, updated_at timestamptz default now());
create table if not exists ecommerce.store_seo_keywords (store_id uuid not null references ecommerce.stores(id) on delete cascade, keyword varchar not null, primary key (store_id, keyword));

create or replace function ecommerce.is_component_styles_admin() returns boolean language plpgsql security definer set search_path to 'ecommerce','public','auth' as $$ declare v_uid uuid := auth.uid(); begin if v_uid is null then return false; end if; if exists (select 1 from ecommerce.user_profiles where id=v_uid and lower(coalesce(role,'')) in ('admin','super_admin')) then return true; end if; if exists (select 1 from ecommerce.store_users su join ecommerce.store_user_roles sur on sur.store_user_id=su.id join ecommerce.roles r on r.id=sur.role_id where su.user_id=v_uid and lower(coalesce(r.role_name,'')) in ('owner','admin','super_admin','store_admin')) then return true; end if; return false; end $$;
create or replace function ecommerce.is_storage_admin() returns boolean language plpgsql security definer set search_path to 'ecommerce','public','auth' as $$ declare v_uid uuid := auth.uid(); begin if v_uid is null then return false; end if; if exists (select 1 from ecommerce.user_profiles where id=v_uid and lower(coalesce(role,'')) in ('admin','super_admin')) then return true; end if; if exists (select 1 from ecommerce.store_users su join ecommerce.store_user_roles sur on sur.store_user_id=su.id join ecommerce.roles r on r.id=sur.role_id where su.user_id=v_uid and lower(coalesce(r.role_name,'')) in ('owner','admin','super_admin','store_admin')) then return true; end if; return false; end $$;
create or replace function ecommerce.increment_item_views(p_item_id uuid) returns integer language plpgsql as $$ declare v_new_count integer; begin if not exists (select 1 from ecommerce.store_items where id=p_item_id) then raise exception 'store item % does not exist in ecommerce.store_items', p_item_id; end if; insert into ecommerce.item_metrics as im (item_id, view_count, updated_at) values (p_item_id,1,timezone('utc',now())) on conflict (item_id) do update set view_count = im.view_count + 1, updated_at = excluded.updated_at returning view_count into v_new_count; return v_new_count; end $$;

create or replace view ecommerce.app_fonts_legacy as select id, font_name, css_font_family as font_family, google_font_url as font_url, false as is_system, is_active, created_at, updated_at, null::uuid as store_id from ecommerce.app_fonts;
create or replace view ecommerce.app_themes_legacy as select t.id, t.theme_name, t.colors as theme_config, v.store_id, coalesce(v.is_current,false) as is_active, t.created_at, t.updated_at from ecommerce.app_themes t left join lateral (select store_id,is_current from ecommerce.app_theme_versions where theme_id=t.id and is_current=true limit 1) v on true;
create or replace view ecommerce.component_styles_legacy as select id, component_name, variables as style_config, store_id, true as is_active, null::timestamptz as created_at, updated_at from ecommerce.component_styles;
create or replace view ecommerce.item_options_legacy as select o.id,o.item_id,o.option_name,coalesce(v.option_values,array[]::varchar[]) as option_values,o.display_order,o.is_required,o.created_at from ecommerce.item_options o left join (select option_id,array_agg(value_text order by display_order,value_text) as option_values from ecommerce.item_option_values group by option_id) v on v.option_id=o.id;
create or replace view ecommerce.store_items_legacy as select si.id,si.item_code,si.item_name,si.item_description,si.item_description_html,si.category_id,si.base_price,si.compare_at_price,si.currency_code,si.is_active,si.is_featured,si.is_available_for_sale,si.track_inventory,coalesce(inv.variant_inventory_quantity,si.inventory_quantity,0) as inventory_quantity,si.low_stock_threshold,si.item_slug,coalesce(seo.seo_title,si.seo_title) as seo_title,coalesce(seo.seo_description,si.seo_description) as seo_description,si.metadata,coalesce(t.tags,si.tags,array[]::varchar[]) as tags,coalesce(img.primary_image_url,si.primary_image_url) as primary_image_url,coalesce(img.primary_image_alt,si.primary_image_alt) as primary_image_alt,si.display_order,coalesce(m.view_count,0) as view_count,si.created_at,si.updated_at,si.store_id from ecommerce.store_items si left join ecommerce.item_seo seo on seo.item_id=si.id left join ecommerce.item_metrics m on m.item_id=si.id left join (select item_id,array_agg(tag order by tag) as tags from ecommerce.item_tags group by item_id) t on t.item_id=si.id left join lateral (select sum(inventory_quantity)::integer as variant_inventory_quantity from ecommerce.item_variants where item_id=si.id) inv on true left join lateral (select image_url as primary_image_url,image_alt as primary_image_alt from ecommerce.item_images where item_id=si.id order by display_order,created_at limit 1) img on true;
create or replace view ecommerce.orders_legacy as select o.id,o.order_number,o.order_date,o.created_at,o.status::text as status,o.customer_type,o.user_id,o.customer_email,o.customer_first_name,o.customer_last_name,o.customer_phone,coalesce(ship.address_line_1,o.shipping_address) as shipping_address,coalesce(ship.city,o.shipping_city) as shipping_city,coalesce(ship.postal_code,o.shipping_postal_code) as shipping_postal_code,coalesce(ship.country,o.shipping_country) as shipping_country,o.shipping_notes,coalesce(pay.payment_method,o.payment_method) as payment_method,coalesce(pay.payment_status,o.payment_status::text) as payment_status,coalesce(pay.payment_reference,o.payment_reference) as payment_reference,o.subtotal,o.shipping_cost,o.tax_amount,o.discount_amount,o.total_amount,o.currency_code,o.notes,o.metadata,o.confirmed_at,o.shipped_at,o.delivered_at,o.cancelled_at,o.updated_at,o.store_id from ecommerce.orders o left join ecommerce.order_addresses ship on ship.order_id=o.id and coalesce(ship.address_type,'shipping')='shipping' left join lateral (select coalesce(provider_payment_method, provider) as payment_method,status::text as payment_status,coalesce(provider_transaction_id, provider_txn_id) as payment_reference from ecommerce.payment_transactions where order_id=o.id order by created_at desc limit 1) pay on true;
create or replace view ecommerce.stores_legacy as select s.id,s.subdomain,s.store_name,s.domain,s.is_active,s.is_public,b.logo_url,b.favicon_url,b.primary_color,b.secondary_color,c.contact_email,c.contact_phone,c.address,s.currency_code,cs.tax_rate,cs.shipping_enabled,cs.free_shipping_threshold,seo.seo_title,seo.seo_description,coalesce(k.seo_keywords,array[]::varchar[]) as seo_keywords,coalesce(i.metadata,'{}'::jsonb) as metadata,i.shopify_store_domain,i.shopify_access_token,s.created_at,s.updated_at,s.deleted_at from ecommerce.stores s left join ecommerce.store_branding b on b.store_id=s.id left join ecommerce.store_contact c on c.store_id=s.id left join ecommerce.store_commerce_settings cs on cs.store_id=s.id left join ecommerce.store_seo seo on seo.store_id=s.id left join ecommerce.store_integrations i on i.store_id=s.id left join (select store_id,array_agg(keyword order by keyword) as seo_keywords from ecommerce.store_seo_keywords group by store_id) k on k.store_id=s.id;

alter table ecommerce.component_styles enable row level security;
drop policy if exists "Component styles public read" on ecommerce.component_styles; create policy "Component styles public read" on ecommerce.component_styles for select to public using (true);
drop policy if exists "Component styles admin insert" on ecommerce.component_styles; create policy "Component styles admin insert" on ecommerce.component_styles for insert to authenticated with check (ecommerce.is_component_styles_admin());
drop policy if exists "Component styles admin update" on ecommerce.component_styles; create policy "Component styles admin update" on ecommerce.component_styles for update to authenticated using (ecommerce.is_component_styles_admin()) with check (ecommerce.is_component_styles_admin());
drop policy if exists "Component styles admin delete" on ecommerce.component_styles; create policy "Component styles admin delete" on ecommerce.component_styles for delete to authenticated using (ecommerce.is_component_styles_admin());

grant usage on schema ecommerce to anon, authenticated, service_role;
grant select on all tables in schema ecommerce to anon, authenticated;
grant insert, update, delete on all tables in schema ecommerce to authenticated;
grant all on all tables in schema ecommerce to service_role;
grant usage, select on all sequences in schema ecommerce to anon, authenticated, service_role;
grant execute on all functions in schema ecommerce to anon, authenticated, service_role;
